function findPrime(numbers) {
    function isPrime(num) {
        if (num < 2) return false;
        for (let i = 2, sqrt = Math.sqrt(num); i <= sqrt; i++)
            if (num % i === 0) return false;
        return true;
    }

    numbers.forEach(num => {
        if (isPrime(num)) console.log(num);
    });
}

// Example usage:
let nums = [1, 2, 3, 4, 7];
findPrime(nums); // Outputs: 2 3 7
```

In this code, we first define a helper function `isPrime` that checks if a given number is prime. Then, we iterate over the input array using `forEach` and call `isPrime` for each number. If a number is prime, we log it to the console. Note that we start checking for factors from 2 and up to the square root of the number, which is an optimization to reduce the number of iterations.

